import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"调查员的烟斗","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/调查员的烟斗.md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/调查员的烟斗.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/调查员的烟斗.md"};function _(l,a,p,i,c,b){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"调查员的烟斗",tabindex:"-1"},[s("调查员的烟斗 "),e("a",{class:"header-anchor",href:"#调查员的烟斗","aria-label":'Permalink to "调查员的烟斗"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="调查员的烟斗-1" tabindex="-1">调查员的烟斗 <a class="header-anchor" href="#调查员的烟斗-1" aria-label="Permalink to &quot;调查员的烟斗&quot;">​</a></h1><p>调查员的烟斗<br> 250<br> 这根长颈烟斗可以用于药草地点燃，不过主要来说还是用于烟丝。<br> 吸烟者能够整轮动作命令一个小型的烟状仆从烟斗中喷出，来执行一些任务 它的外观是一束烟灰色的小型云雾（无法飞行也不会被风吹散取），可以无限喷出，同时只能存在一个。<br> 消解烟雾仆从是一个迅捷动作。<br> 购买者需要自己准备烟丝或草药，任何烟丝都可。</p><p>烟雾仆从不会触发效果和被影响，通常来说也能避开任何陷阱、伤害、必死的区域，这是被动的，意味着你无法命令其利用这一点起到作用，且仍然会因有意识的攻击而消散。<br> 烟雾仆从具有力量5/敏捷5/耐力3，感知3/智力3/决心1，沉着1/操纵1/风度1。<br> 技能为运动3-平衡1，游泳1，跳跃1/求生3-追踪3/射击0/武技0，学识1-解读1/器用0/手艺1-修复1/专注0，洞察1-调查1/隐秘1-专业潜藏1/表达0/社交0，衍生属性如常计算，可以进行打杂或传递消息一类的行为，但在进行社交检定时自动失败。<br> 虽然烟雾仆从视为随从模板，但不能够获得任何强化，也无法参与战斗。<br> 计算体积时，烟雾仆从视为1-5点可自由改变体积，不影响数据（以5计算），但影响碰撞体积。</p><p>若在购买时额外支付D+500分，烟雾仆从则具有等同基础速度的飞行能力，机动性普通。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
